phase1.code:
#include <iostream>
#include <string>

class Player {
public:
    std::string name;
    int health;

    Player(std::string n, int h) : name(n), health(h) {}

    void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }
};

// --- Pass by value ---
void passByValue(Player p) {
    p.health = 999;
    std::cout << "Inside passByValue: ";
    p.display();
}

// --- Pass by reference ---
void passByReference(Player& p) {
    p.health = 999;
    std::cout << "Inside passByReference: ";
    p.display();
}

// --- Pass by const reference ---
void passByConstReference(const Player& p) {
    // p.health = 999;  // ERROR! Can't modify const
    std::cout << "Inside passByConstReference: ";
    p.display();
}

// --- Pass by pointer ---
void passByPointer(Player* p) {
    if (p != nullptr) {
        p->health = 999;
        std::cout << "Inside passByPointer: ";
        p->display();
    }
}

// --- Pass by value (large object) ---
void processLargeObject(std::string str) {
    // Copies the entire string
    std::cout << "String length: " << str.length() << std::endl;
}

// --- Pass by const reference (large object) ---
void processLargeObjectEfficient(const std::string& str) {
    // No copy!
    std::cout << "String length: " << str.length() << std::endl;
}

int main() {
    std::cout << "=== Passing by Value vs Reference vs Pointer ===" << std::endl;

    Player hero("Aragorn", 100);

    std::cout << "\n--- Pass by Value ---" << std::endl;
    std::cout << "Before: ";
    hero.display();
    passByValue(hero);  // Copies the object
    std::cout << "After: ";
    hero.display();  // Unchanged!

    std::cout << "\n--- Pass by Reference ---" << std::endl;
    std::cout << "Before: ";
    hero.display();
    passByReference(hero);  // References the object
    std::cout << "After: ";
    hero.display();  // Changed!

    std::cout << "\n--- Pass by Const Reference ---" << std::endl;
    passByConstReference(hero);  // Read-only access

    std::cout << "\n--- Pass by Pointer ---" << std::endl;
    std::cout << "Before: ";
    hero.display();
    passByPointer(&hero);  // Pass address
    std::cout << "After: ";
    hero.display();  // Changed!

    // Performance comparison
    std::cout << "\n--- Performance Considerations ---" << std::endl;
    std::string longString(100000, 'X');  // Large string

    std::cout << "Pass by value (copies): ";
    processLargeObject(longString);

    std::cout << "Pass by const reference (no copy): ";
    processLargeObjectEfficient(longString);

    std::cout << "\n--- Summary ---" << std::endl;
    std::cout << "Pass by value:    copies data, original unchanged" << std::endl;
    std::cout << "Pass by reference: no copy, can modify original" << std::endl;
    std::cout << "Pass by const ref: no copy, read-only" << std::endl;
    std::cout << "Pass by pointer:   no copy, can modify (check null!)" << std::endl;

    return 0;
}

