phase3.solution:
#include <iostream>
#include <string>

void modifyByValue(int x) {
    x = 999;
    std::cout << "Inside modifyByValue: x = " << x << std::endl;
}

void modifyByReference(int& x) {
    x = 999;
    std::cout << "Inside modifyByReference: x = " << x << std::endl;
}

void modifyByPointer(int* x) {
    if (x != nullptr) {
        *x = 999;
        std::cout << "Inside modifyByPointer: x = " << *x << std::endl;
    }
}

void stringByValue(std::string s) {
    std::cout << "String by value length: " << s.length() << std::endl;
}

void stringByConstRef(const std::string& s) {
    std::cout << "String by const ref length: " << s.length() << std::endl;
}

int main() {
    int num = 10;
    std::cout << "Initial num: " << num << std::endl;

    modifyByValue(num);
    std::cout << "After by value: " << num << std::endl;

    modifyByReference(num);
    std::cout << "After by reference: " << num << std::endl;

    num = 10;
    modifyByPointer(&num);
    std::cout << "After by pointer: " << num << std::endl;

    std::string bigString(1000, 'X');
    std::cout << "\n=== String passing ===" << std::endl;
    stringByValue(bigString);
    stringByConstRef(bigString);

    return 0;
}
